// public/assets/js/d3_codeStructure.js
// Rendern → Repaint-Controller bauen → Initial repaint → später wiederverwenden

import CodeGraphData from "./codeGraph/data.js";
import CodeGraphInteractions from "./codeGraph/interactions.js";
import { renderTypeHulls } from "./codeGraph/render.hulls.js";
import * as CodeGraphUI from "./codeGraph/ui.js";
import { ensureTooltip, showTooltip, moveTooltip, hideTooltip } from "./codeGraph/ui.tooltip.js";
import { wireLegendAndFilters } from "./codeGraph/ui.filters.js";
import { assertCodeStructureDeps, buildGraphDiagnosticsPanel } from "./codeGraph/ui.diagnostics.js";
import { createSimulation } from "./codeGraph/render.simulation.js";
import { buildTooltipHtml } from "./codeGraph/render.tooltip.js";
import { normalizeLinkType } from "./codeGraph/shared.js";
import {
  makeEncoders,
  isFunctionNode,
  isUnusedFunctionNode,
  getFunctionRingWidth,
  toSafeInt
} from "./codeGraph/render.encoders.js";

import { makeRepaint } from "./codeGraph/render.repaint.js";

/**
 * D3 Code Structure Graph Renderer
 * ===========================
 *
 * Purpose
 * -------
 * Renders a dependency graph (files/modules) for NodeAnalyzer metrics output.
 * This script is UI-only and consumes a JSON payload generated by the backend.
 *
 * Frontend Module Dependencies
 * ----------------------------
 * - CodeGraphData.normalize(metrics) -> { nodes, links }
 * - CodeGraphInteractions.attachNodeInteractions(nodeSel, opts)
 * - renderTypeHulls(hullGroup, nodes, clusterColorScale)
 * - CodeGraphUI.escapeHtml(...)
 * - wireLegendAndFilters(...)
 * - buildGraphDiagnosticsPanel(...)
 * - createSimulation(...)
 * - buildTooltipHtml(...)
 *
 * Integration Hooks
 * -----------------
 * - opts.onNodeSelected(node): optional async hook on node click (passed to init)
 * - opts.initHighlightId: optional node id to highlight after initial render
 *
 * Return Value
 * -----------
 * initcodeStructureChart(...) returns a controller object:
 * - { svg, nodes, links, simulation, markChanged(), destroy() }
 *
 * The renderer stays focused on orchestration and render lifecycle.
 */

"use strict";

/* ======================================================================
   Configuration (Colors)
====================================================================== */

// Canonical semantic colors (backend contract): `node.group`
// Groups are intentionally coarse and stable across projects.
const NODE_GROUP_COLORS = {
  root: "#111827",   // near-black
  dir: "#6c8cff",    // blue-ish
  code: "#adb5bd",   // neutral grey (tone varies by complexity)
  doc: "#2ec4b6",    // teal
  data: "#ff9933",   // orange
  image: "#9d4edd"   // purple
};

// Semantic edge colors shared with the legend/filter panel.
const LINK_TYPE_COLORS = {
  include: "#FF6B6B",
  use: "#4D96FF",
  extends: "#06D6A0",
  call: "#8338EC",
  default: "#BBBBBB"
};

// Highlight color for exported function nodes
const EXPORTED_FUNCTION_COLOR = "var(--graph-exported-function-ring)";
const GRAPH_ZOOM_MIN = 0.4;
const GRAPH_ZOOM_MAX = 2.2;
const GRAPH_ZOOM_DEFAULT = 1;

// Stable cluster palette for hull rendering.
const clusterColor = d3.scaleOrdinal(d3.schemeSet3);

/**
 * Show a browser alert once per page-load for a given key.
 * Prevents re-run spam when the graph is re-rendered.
 * @param {string} key Deduplication key.
 * @param {string} message Alert text.
 */
function alertOnce(key, message) {
  try {
    const g = (window.__codeStructureAlertOnce = window.__codeStructureAlertOnce || Object.create(null));
    if (g[key]) return;
    g[key] = true;
    window.alert(message);
  } catch {
    // ignore
  }
}


/* ======================================================================
   Public Entrypoint
====================================================================== */

/**
 * Main render entrypoint.
 *
 * Responsibilities:
 * - Reset SVG and build render layers
 * - Normalize backend metrics into {nodes, links}
 * - Derive force layout defaults and run simulation
 * - Render links, nodes, labels, hulls, and integrate UI helpers
 */
export function initcodeStructureChart(svgId, metrics, opts = {}) {
  // 0) Validate external helpers early (fail loudly in dev)
  assertCodeStructureDeps({
    d3Global: window.d3,
    CodeGraphData,
    CodeGraphInteractions,
    CodeGraphUI,
    renderTypeHulls
  });

  // Optional callback supplied by the app (no window bridge).
  // Called when the user clicks a node in the graph.
  const onNodeSelected = typeof opts?.onNodeSelected === "function" ? opts.onNodeSelected : null;

  // Optional: deep-link highlight (formerly `window.initHighlightId`).
  const initHighlightId = String(opts?.initHighlightId || "").trim();

  // -------------------------------------------------------------------
  // Local helpers (keep renderer self-contained, no extra files)
  // -------------------------------------------------------------------


  /**
   * Resolve the target SVG and clear previous render output.
   */
  function selectAndResetSvg(svgId) {
    const svg = d3.select("#" + svgId);
    if (svg.empty()) {
      console.warn("SVG not found:", svgId);
      return null;
    }
    svg.selectAll("*").remove();
    return svg;
  }

  /**
   * Apply the canonical responsive SVG viewport.
   */
  function applyViewBox(svg, width, height) {
    svg
      .attr("viewBox", `0 0 ${width} ${height}`)
      .attr("preserveAspectRatio", "xMidYMid meet");
  }

  function measureSvgViewport(svg) {
    const svgNode = svg?.node?.();
    const host = svgNode?.parentElement;

    const width = Math.max(
      host?.clientWidth || 0,
      svgNode?.clientWidth || 0,
      360
    );

    const height = Math.max(
      host?.clientHeight || 0,
      width,
      360
    );

    return { width, height };
  }

  /**
   * Build the ordered SVG layer stack used by the renderer.
   */
  function buildLayers(svg) {
    // IMPORTANT: highlight is between node shapes and node labels (prevents ring-over-text)
    const zoomLayer = svg.append("g");
    return {
      zoomLayer,
      hullGroup: zoomLayer.append("g").attr("class", "hulls"),
      linkGroup: zoomLayer.append("g").attr("class", "links"),
      nodeShapeGroup: zoomLayer.append("g").attr("class", "node-shapes"),
      highlightLayer: zoomLayer.append("g").attr("class", "highlight-layer"),
      nodeLabelGroup: zoomLayer.append("g").attr("class", "node-labels"),
    };
  }

  /**
   * Attach pan/zoom behavior to the root SVG.
   */
  function installZoom(svg, zoomLayer) {
    let currentTransform = d3.zoomIdentity;

    const zoom = d3.zoom()
      .scaleExtent([GRAPH_ZOOM_MIN, GRAPH_ZOOM_MAX])
      .filter((event) => {
        const type = String(event?.type || "");
        if (type === "wheel" || type === "dblclick") return false;
        if (type.startsWith("touch")) return false;
        return !event?.button;
      })
      .on("zoom", (event) => {
        currentTransform = event.transform;
        zoomLayer.attr("transform", currentTransform);
      });

    svg.call(zoom);
    zoomLayer.attr("transform", currentTransform);

    function clampZoomScale(value) {
      const scale = Number(value);
      if (!Number.isFinite(scale)) return GRAPH_ZOOM_DEFAULT;
      return Math.max(GRAPH_ZOOM_MIN, Math.min(GRAPH_ZOOM_MAX, scale));
    }

    function getZoom() {
      const scale = Number(currentTransform?.k);
      return Number.isFinite(scale) ? scale : GRAPH_ZOOM_DEFAULT;
    }

    function setZoom(value) {
      const nextScale = clampZoomScale(value);
      svg.call(zoom.scaleTo, nextScale);
      return nextScale;
    }

    function destroyZoom() {
      try { svg.on(".zoom", null); } catch { }
    }

    return {
      getZoom,
      setZoom,
      destroyZoom
    };
  }

  /**
   * Resolve the shared tooltip container best-effort.
   */
  function getTooltipOrNull() {
    // Tooltip module is optional but bundled in this project.
    try {
      return ensureTooltip();
    } catch {
      return null;
    }
  }

  /**
   * Normalize backend metrics into renderer-ready nodes and links.
   */
  function normalizeGraph(metrics) {
    if (!CodeGraphData?.normalize) {
      throw new Error("CodeGraphData.normalize missing.");
    }
    return CodeGraphData.normalize(metrics);
  }

  /**
   * Validate that nodes provide the canonical `group` field the renderer expects.
   *
   * Why this exists:
   * - The renderer uses `node.group` to pick stable colors/clusters.
   * - During refactors it’s easy to forget to emit `group` in the backend.
   *
   * Behavior:
   * - Runs best-effort diagnostics via CodeGraphData.validateNodeGroups.
   * - Shows a single alert (deduped by alertOnce) with a few examples.
   * - Fail-soft: never throws.
   *
   * @param {any[]} nodes
   */
  function validateGroupsOnce(nodes) {
    try {
      const diag = getGroupDiagnostics(nodes);
      if (!diag) return;

      // Nothing to report -> keep quiet.
      if (diag.missing.length === 0 && diag.unknown.length === 0) return;

      alertOnce("missing-or-unknown-node-group", buildGroupAlertMessage(diag));
    } catch {
      // ignore
    }
  }

  /**
   * Run group diagnostics (best-effort) and normalize the result shape.
   * @param {any[]} nodes
   * @returns {{missing:any[], unknown:any[]}|null}
   */
  function getGroupDiagnostics(nodes) {
    const validate = CodeGraphData?.validateNodeGroups;
    if (typeof validate !== "function") return null;

    const raw = validate(nodes, NODE_GROUP_COLORS) || Object.create(null);
    return {
      missing: Array.isArray(raw.missing) ? raw.missing : [],
      unknown: Array.isArray(raw.unknown) ? raw.unknown : [],
    };
  }

  /**
   * Build a user-facing alert message from diagnostics.
   * @param {{missing:any[], unknown:any[]}} diag
   */
  function buildGroupAlertMessage(diag) {
    const parts = [];

    const missingExamples = formatMissingExamples(diag.missing);
    const unknownExamples = formatUnknownExamples(diag.unknown);

    if (diag.missing.length) {
      parts.push("Fehlende node.group (max 3 Beispiele):\n" + missingExamples);
    }

    if (diag.unknown.length) {
      parts.push("Unbekannte node.group (max 3 Beispiele):\n" + unknownExamples);
    }

    return (
      "NodeAnalyzer: Node-Farben/Cluster benötigen node.group im JSON.\n" +
      "Fix: Stelle sicher, dass das Backend `group` setzt (root/dir/code/doc/data/image).\n\n" +
      parts.join("\n\n")
    );
  }

  /**
   * @param {any[]} missing
   * @returns {string}
   */
  function formatMissingExamples(missing) {
    const ids = (Array.isArray(missing) ? missing : [])
      .slice(0, 3)
      .map((n) => String(n?.id || n?.file || "(unknown)"));

    return ids.length ? ids.map((x) => `- ${x}`).join("\n") : "- (keine Beispiele)";
  }

  /**
   * Format up to three unknown `node.group` examples for the diagnostics alert.
   *
   * @param {any[]} unknown
   * @returns {string}
   */
  function formatUnknownExamples(unknown) {
    const list = takeFirstUnknown(unknown, 3);
    if (list.length === 0) return "- (keine Beispiele)";

    const lines = list.map(formatUnknownExampleLine);
    return lines.join("\n");
  }

  /** Ensure we operate on a small normalized array. */
  function takeFirstUnknown(arr, max) {
    if (!Array.isArray(arr)) return [];
    return arr.slice(0, max);
  }

  /** Format a single unknown-group example line. */
  function formatUnknownExampleLine(n) {
    const group = readUnknownGroup(n);
    const id = readUnknownId(n);
    return `- ${group}  @  ${id}`;
  }

  /** @param {any} n */
  function readUnknownGroup(n) {
    return String(n?.group || "?");
  }

  /** @param {any} n */
  function readUnknownId(n) {
    return String(n?.id || n?.file || "(unknown)");
  }

  /**
   * Seed live-change flags expected by the repaint pipeline.
   */
  function initLiveChangeState(nodes) {
    for (const n of nodes) {
      if (typeof n._changed !== "boolean") n._changed = false;
      if (typeof n._lastChangedAt !== "string") n._lastChangedAt = "";
      if (typeof n._lastChangeEv !== "string") n._lastChangeEv = "";
    }
  }



  /**
   * Render link lines for the normalized edge set.
   */
  function renderLinks(linkGroup, links, enc) {
    const getEdgeColor = (typeof enc?.getEdgeColor === "function")
      ? enc.getEdgeColor
      : ((d) => LINK_TYPE_COLORS[normalizeLinkType(d, "use")] || LINK_TYPE_COLORS.default);

    const getEdgeWidth = (typeof enc?.getEdgeWidth === "function")
      ? enc.getEdgeWidth
      : (() => 1.2);

    return linkGroup.selectAll("line")
      .data(links)
      .enter()
      .append("line")
      .attr("class", (d) => `link ${normalizeLinkType(d, "use")}`)
      .attr("data-link-type", (d) => normalizeLinkType(d, "use"))
      .attr("stroke", (d) => getEdgeColor(d))
      .attr("stroke-width", (d) => getEdgeWidth(d))
      .attr("marker-end", (d) => (normalizeLinkType(d, "use") === "include" ? null : "url(#arrowhead)"));
  }

  /**
   * Render node groups, bodies, function rings, and unused badges.
   */
  function renderNodes(nodeShapeGroup, nodes, enc) {
    const nodeShapeSel = nodeShapeGroup.selectAll("g")
      .data(nodes)
      .enter()
      .append("g")
      .attr("class", "node");

    const nodeBodySel = nodeShapeSel.append("circle")
      .attr("class", "node-body")
      .attr("r", (d) => enc.getRadius(d))
      .attr("fill", (d) => enc.getNodeColor(d))
      .attr("stroke", (d) => enc.getNodeStroke(d))
      .attr("stroke-width", (d) => enc.getNodeStrokeWidth(d));

    const fnRingSel = nodeShapeSel.append("circle")
      .attr("class", (d) => (isFunctionNode(d) ? "node-ring is-function" : "node-ring"))
      .attr("r", (d) => enc.getRadius(d) + 4)
      .attr("fill", "none")
      .attr("stroke", (d) => {
        if (!isFunctionNode(d)) return "transparent";
        return (d?.exported === true) ? EXPORTED_FUNCTION_COLOR : "rgba(0,0,0,0.25)";
      })
      .attr("stroke-opacity", (d) => (isFunctionNode(d) ? 0.95 : 0))
      .attr("stroke-width", (d) => (isFunctionNode(d) ? getFunctionRingWidth(d) : 0))
      .attr("pointer-events", "none");

    const unusedBadgeSel = nodeShapeSel.append("text")
      .attr("class", "badge-unused")
      .attr("text-anchor", "middle")
      .attr("dominant-baseline", "middle")
      .style("font-weight", "700")
      .style("font-size", "12px")
      .style("paint-order", "stroke")
      .style("stroke-width", "3px")
      .style("pointer-events", "none")
      .text("!");

    return { nodeShapeSel, nodeBodySel, fnRingSel, unusedBadgeSel };
  }

  /**
   * Render transparent hit areas for pointer interaction and tooltips.
   */
  function renderHits(nodeShapeSel, enc, tooltip) {
    // Transparent hit area (slightly larger, easier click/drag)
    return nodeShapeSel.append("circle")
      .attr("class", "node-hit")
      .attr("r", (d) => enc.getRadius(d) + 8)
      .attr("fill", "transparent")
      .attr("stroke", "transparent")
      .style("cursor", "pointer")
      .on("mouseover", (event, d) => {
        if (!tooltip) return;
        const html = buildTooltipHtml(d, {
          escapeHtml: CodeGraphUI?.escapeHtml,
          isFunctionNode,
          toSafeInt
        });
        showTooltip(tooltip, event, html);
      })
      .on("mousemove", (event) => {
        if (!tooltip) return;
        moveTooltip(tooltip, event);
      })
      .on("mouseout", () => {
        if (!tooltip) return;
        hideTooltip(tooltip);
      });
  }

  /**
   * Render node labels in the dedicated label layer.
   */
  function renderLabels(nodeLabelGroup, nodes, enc) {
    return nodeLabelGroup.selectAll("text")
      .data(nodes)
      .enter()
      .append("text")
      .attr("class", "node-label")
      .attr("x", (d) => -enc.getRadius(d) - 6)
      .attr("y", 4)
      .style("font-size", "11px")
      .style("font-family", "sans-serif")
      .style("pointer-events", "none")
      .style("fill", "#444")
      .text((d) => d.__displayLabel || (d.id || "").split("/").pop());
  }


  /**
   * Attach node interaction behavior supplied by the interaction module.
   */
  function wireInteractions({ nodeShapeSel, simulation, highlightLayer }) {
    CodeGraphInteractions.attachNodeInteractions(nodeShapeSel, {
      simulation,
      thresholdPx: 5,
      onSelected: async (node) => {
        if (onNodeSelected) {
          await onNodeSelected(node);
        }
        if (window.NAV_REDIRECT_ON_CLICK === true) {
          handleNodeClick(node);
        }

        CodeGraphInteractions.drawHighlight(node, highlightLayer);
      },
      enableLegacyRedirect: false,
      legacyRedirect: null
    });
  }

  /**
   * Bind the simulation tick loop to rendered selections.
   */
  function wireSimulationTicks({ simulation, linkSel, nodeShapeSel, labelSel, highlightLayer, hullGroup, nodes }) {
    simulation.on("tick", () => {
      linkSel
        .attr("x1", (d) => d.source.x)
        .attr("y1", (d) => d.source.y)
        .attr("x2", (d) => d.target.x)
        .attr("y2", (d) => d.target.y);

      nodeShapeSel.attr("transform", (d) => `translate(${d.x},${d.y})`);
      labelSel.attr("transform", (d) => `translate(${d.x},${d.y})`);


      CodeGraphInteractions.anchorHighlight(highlightLayer);
      renderTypeHulls(hullGroup, nodes, clusterColor);
    });
  }

  /**
   * Attach post-layout diagnostics once the simulation settles.
   */
  function wireSimulationEnd({ simulation, svgId, nodes, links, width, height }) {
    simulation.on("end", () => {
      buildGraphDiagnosticsPanel(svgId, nodes, links, width, height);
    });
  }

  /**
   * Restore an initial highlight requested by the host app.
   */
  function restoreHighlightIfNeeded({ nodes, highlightLayer }) {
    // If the host app requests an initial highlight (e.g. deep-link), restore it
    // AFTER the graph is rendered and the highlight layer exists.
    if (!initHighlightId) return;

    const match = nodes.find((n) => n.id === initHighlightId);
    if (!match) return;

    // Highlight helpers live in CodeGraphInteractions (keeps renderer thinner).
    if (window.CodeGraphInteractions?.drawHighlight) {
      window.CodeGraphInteractions.drawHighlight(match, highlightLayer);
    }
  }

  // -------------------------------------------------------------------
  // Change-mark controller (host hook)
  // -------------------------------------------------------------------

  /**
   * Normalize one host-side change event into the renderer contract.
   */
  function normalizeChangeEvent(evtOrId) {
    const evt = toChangeEventObject(evtOrId);
    const id = readChangeId(evt);
    if (!id) return null;

    return {
      id,
      ev: readChangeEv(evt),
      at: readChangeAt(evt)
    };
  }

  /**
   * Normalize host input into an event-like object.
   * Accepts either a string node id or an event object.
   *
   * @param {any} evtOrId
   * @returns {{id?:any, ev?:any, at?:any}|null}
   */
  function toChangeEventObject(evtOrId) {
    if (evtOrId == null) return null;
    return (typeof evtOrId === "string") ? { id: evtOrId } : evtOrId;
  }

  /**
   * Extract and normalize the changed node id from an event.
   *
   * @param {{id?:any}|null} evt
   * @returns {string}
   */
  function readChangeId(evt) {
    return String(evt?.id || "").trim();
  }

  /**
   * Extract and normalize the change event label.
   *
   * @param {{ev?:any}|null} evt
   * @returns {string}
   */
  function readChangeEv(evt) {
    return String(evt?.ev || "change");
  }

  /**
   * Extract and normalize the change timestamp.
   *
   * @param {{at?:any}|null} evt
   * @returns {string}
   */
  function readChangeAt(evt) {
    return String(evt?.at || "");
  }

  /**
   * Clear the single-selection changed marker from all nodes.
   */
  function clearChangedFlags(list) {
    for (const n of list) {
      if (n && typeof n === "object") n._changed = false;
    }
  }

  /**
   * Best-effort lookup by exact node id.
   * @param {any[]} list
   * @param {string} id
   * @returns {any|null}
   */
  function findNodeById(list, id) {
    const wanted = String(id || "");
    if (!wanted) return null;
    return list.find((n) => n && n.id === wanted) || null;
  }

  /**
   * Apply the change metadata to a node.
   * @param {any} node
   * @param {{ev:string, at:string}} evt
   */
  function applyChange(node, evt) {
    node._changed = true;
    node._lastChangeEv = evt.ev;
    node._lastChangedAt = evt.at;
  }

  /**
   * Build the host-facing change marker controller.
   *
   * The host can call `markChanged(...)` after watch/SSE events so the graph
   * reflects the newest changed node without a full re-render.
   */
  function createMarkChangedController(nodes, repaintNodes) {
    const list = Array.isArray(nodes) ? nodes : [];
    const repaint = (typeof repaintNodes === "function") ? repaintNodes : () => { };

    /**
     * Mark exactly one node as "changed".
     *
     * Used by the host app when it receives file change events (watch/SSE).
     * Replaces the old global `window.graphMarkChanged(...)` hook.
     *
     * @param {string|{id?:string, ev?:string, at?:string}} evtOrId
     */
    function markChanged(evtOrId) {
      const evt = normalizeChangeEvent(evtOrId);
      if (!evt) return;

      clearChangedFlags(list);

      const hit = findNodeById(list, evt.id);
      if (!hit) return;

      applyChange(hit, evt);
      repaint();
    }

    return { markChanged };
  }

  // -------------------------------------------------------------------
  // Legend + Filter wiring
  // -------------------------------------------------------------------

  /**
   * Pick only the D3 selections needed for live legend/filter wiring.
   */
  function pickLegendSelections(sels) {
    const s = (sels && typeof sels === "object") ? sels : Object.create(null);
    return {
      nodeShapeSel: s.nodeShapeSel,
      labelSel: s.labelSel,
      linkSel: s.linkSel,
      unusedBadgeSel: s.unusedBadgeSel,
      hullGroup: s.hullGroup,
    };
  }

  /**
   * Read the panel render hook.
   */
  function readLegendPanelDeps() {
    return {
      buildLegendFilterPanel: CodeGraphUI?.buildLegendFilterPanel,
      attachLegendFilterWiring: CodeGraphUI?.attachLegendFilterWiring,
    };
  }

  /**
   * Read the legend/filter state hooks.
   */
  function readLegendStateDeps() {
    return {
      getState: CodeGraphUI?.getState,
      stateBySvgId: CodeGraphUI?.stateBySvgId,
      dispatchFiltersChanged: CodeGraphUI?.dispatchFiltersChanged,
      updateGroupFilter: CodeGraphUI?.updateGroupFilter,
      updateLinkFilter: CodeGraphUI?.updateLinkFilter,
      updateOptionFilter: CodeGraphUI?.updateOptionFilter,
    };
  }

  /**
   * Read the shared escaping hook.
   */
  function readLegendTextDeps() {
    return {
      escapeHtml: CodeGraphUI?.escapeHtml,
    };
  }

  /**
   * Read the UI hook subset needed by legend/filter wiring.
   */
  function readLegendFilterUiDeps() {
    return {
      ...readLegendPanelDeps(),
      ...readLegendStateDeps(),
      ...readLegendTextDeps(),
    };
  }

  /**
   * Read the static legend color dependencies.
   */
  function readLegendFilterColorDeps() {
    return {
      nodeGroupColors: NODE_GROUP_COLORS,
      linkTypeColors: LINK_TYPE_COLORS,
    };
  }

  /**
   * Collect the dependencies required by the legend/filter orchestration layer.
   */
  function buildLegendFilterDeps() {
    return {
      ...readLegendFilterUiDeps(),
      ...readLegendFilterColorDeps(),
    };
  }

  /**
   * Build one normalized legend/filter wiring context for the current graph.
   */
  function buildLegendFilterCtx(cfg) {
    const c = (cfg && typeof cfg === "object") ? cfg : Object.create(null);
    return {
      svgId: String(c.svgId || ""),
      nodes: Array.isArray(c.nodes) ? c.nodes : [],
      links: Array.isArray(c.links) ? c.links : [],
      sels: pickLegendSelections(c.sels),
      deps: buildLegendFilterDeps(),
    };
  }



  // -------------------------------------------------------------------
  // 1) Setup SVG
  // -------------------------------------------------------------------
  const svg = selectAndResetSvg(svgId);
  if (!svg) return;

  const { width, height } = measureSvgViewport(svg);
  applyViewBox(svg, width, height);

  const layers = buildLayers(svg);
  const tooltip = getTooltipOrNull();

  const zoomController = installZoom(svg, layers.zoomLayer);
  defineArrowMarker(svg);

  // -------------------------------------------------------------------
  // 2) Normalize + validate + init render state
  // -------------------------------------------------------------------
  const { nodes, links } = normalizeGraph(metrics);
  validateGroupsOnce(nodes);
  initLiveChangeState(nodes);

  // -------------------------------------------------------------------
  // 3) Encoders + simulation
  // -------------------------------------------------------------------
  // Visual encoders live in `codeGraph/render.encoders.js`.
  const enc = makeEncoders(nodes);
  // Force simulation now lives in `codeGraph/render.simulation.js`.
  const simulation = createSimulation({ nodes, links, width, height, getRadius: enc.getRadius });

  // -------------------------------------------------------------------
  // 4) Render
  // -------------------------------------------------------------------
  const linkSel = renderLinks(layers.linkGroup, links, enc);

  const { nodeShapeSel, nodeBodySel, fnRingSel, unusedBadgeSel } =
    renderNodes(layers.nodeShapeGroup, nodes, enc);

  renderHits(nodeShapeSel, enc, tooltip);

  const labelSel = renderLabels(layers.nodeLabelGroup, nodes, enc);

  // -------------------------------------------------------------------
  // 5) Repaint + initial apply (unused styles, rings, badges)
  // -------------------------------------------------------------------
  // Repaint helpers now live in `codeGraph/render.repaint.js`.
  const repaintNodes = makeRepaint({
    nodes,
    enc,
    nodeBodySel,
    fnRingSel,
    unusedBadgeSel,
    labelSel,
    isFunctionNode,
    isUnusedFunctionNode,
    getFunctionRingWidth,
    exportedFunctionColor: EXPORTED_FUNCTION_COLOR
  });
  repaintNodes();


  // -------------------------------------------------------------------
  // 6) Wire interactions + simulation loops
  // -------------------------------------------------------------------
  wireInteractions({ nodeShapeSel, simulation, highlightLayer: layers.highlightLayer });

  wireSimulationTicks({
    simulation,
    linkSel,
    nodeShapeSel,
    labelSel,
    highlightLayer: layers.highlightLayer,
    hullGroup: layers.hullGroup,
    nodes
  });

  wireSimulationEnd({ simulation, svgId, nodes, links, width, height });
  restoreHighlightIfNeeded({ nodes, highlightLayer: layers.highlightLayer });

  // -------------------------------------------------------------------
  // 7) UI integrations (legend/filter + event wiring)
  // -------------------------------------------------------------------
  // Bundle legend/filter wiring inputs once.
  const legendFilterCtx = buildLegendFilterCtx({
    svgId,
    nodes,
    links,
    sels: {
      nodeShapeSel,
      labelSel,
      linkSel,
      unusedBadgeSel,
      hullGroup: layers.hullGroup
    }
  });

  wireLegendAndFilters(legendFilterCtx);

  // -------------------------------------------------------------------
  // 8) Controller helpers (no window bridge)
  // -------------------------------------------------------------------
  const { markChanged } = createMarkChangedController(nodes, repaintNodes);

  // -------------------------------------------------------------------
  // 9) Update graph header (app name + function count + LOC)
  // -------------------------------------------------------------------
  // This must run *after* normalization and render, because it needs the
  // final nodes array.
  //
  // Source of app name (best-effort):
  // - metrics.appName / metrics.meta.appName (preferred)
  // - fallback: ""
  try {
    const appName = String(metrics?.appName ?? metrics?.meta?.appName ?? "").trim();

    if (CodeGraphUI?.updateGraphHeader) {
      const fnCount = nodes.filter((n) => String(n?.type || n?.kind) === "function").length;

      let loc = 0;
      for (const n of nodes) {
        loc += Number(n?.lines ?? n?.locLines ?? 0) || 0;
      }

      CodeGraphUI.updateGraphHeader({
        appName,
        functions: fnCount,
        loc
      });
    }
  } catch {
    // ignore
  }

  /**
   * Tear down simulation, tooltip, and SVG content for this graph instance.
   */
  function destroy() {
    try { zoomController?.destroyZoom?.(); } catch { }
    try { simulation?.stop?.(); } catch { }
    try { hideTooltip(tooltip); } catch { }
    try { svg?.selectAll?.("*")?.remove?.(); } catch { }
  }

  return {
    svg,
    nodes,
    links,
    simulation,
    markChanged,
    getZoom: zoomController?.getZoom,
    setZoom: zoomController?.setZoom,
    destroy
  };
};


/* ======================================================================
   Marker / defs
====================================================================== */

/**
 * Define the shared arrowhead marker used by directed graph edges.
 * The marker inherits the stroke color via `currentColor`.
 *
 * @param {any} svg d3 selection for the root svg.
 */
function defineArrowMarker(svg) {
  svg.append("defs")
    .append("marker")
    .attr("id", "arrowhead")
    .attr("viewBox", "-0 -5 10 10")
    .attr("refX", 23)
    .attr("refY", 0)
    .attr("markerWidth", 6)
    .attr("markerHeight", 6)
    .attr("orient", "auto")
    .append("path")
    .attr("d", "M0,-5L10,0L0,5")
    .attr("fill", "currentColor")
    .style("stroke", "none");
}

// Run once at module init (dev help).
assertCodeStructureDeps({
  d3Global: window.d3,
  CodeGraphData,
  CodeGraphInteractions,
  CodeGraphUI,
  renderTypeHulls
});
